insert into public.products (id,name,category,brand,price,stock,description,images,features,active,sort) values
('inv01','Silla Premium baby Modelo Rumi','convertibles','Premium Baby',0,1,'La Silla de Carro Rumi de Premium Baby es un sistema infantil multietapa diseñado para acompañar a tu hijo desde su nacimiento hasta los 12 años aproximadamente.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv01-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv01-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv01-3.jpg"]'::jsonb,'["Rango de Peso: Soporta desde el nacimiento hasta los 45 kg.","Orientación a Contramarcha: Diseñada para bebés desde los 2.2 kg hasta los 18 kg (aproximadamente hasta los 4 años).","Orientación a Favor de la Marcha: Apta para niños desde los 12 kg hasta los 30 kg.","Arnés de Seguridad: Sistema de arnés de 5 puntos con almohadillas protectoras ajustables en hombros y caderas.","Reclinación: Cuenta con 2 posiciones de reclinado ajustables para mayor comodidad del bebé en trayectos largos.","Estructura: Diseño acolchado y envolvente (multietapa) que brinda mayor soporte."]'::jsonb,true,1),
('inv02','I Hero 360 Giratória Premium Baby','giro-360','Premium Baby',0,0,'La Silla de auto iHero - Premium Baby es un sistema de retención infantil diseñado para proteger a tu hijo desde el nacimiento hasta los 12 años (aprox. 36 kg). Destaca por su base giratoria de 360°, que facilita colocar y sacar a tu bebé del vehículo con un solo movimiento.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv02-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv02-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv02-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv02-4.jpg"]'::jsonb,'["Rango de uso: Desde los 40 cm hasta los 150 cm de altura","Posiciones de reclinado: Cuenta con 4 posiciones a contramarcha y 5 posiciones a favor de la marcha.","Confort: Cabecera regulable en altura y reductor acolchado extraíble para recién nacidos.","Contramarcha: Desde recién nacido hasta los 4 años aprox. (40 a 105 cm).","En marcha: Desde 1 año hasta los 4 años aprox. (76 a 105 cm).","Tipo elevador: Desde los 4 a 12 años aprox. (100 a 150 cm) usando el cinturón de seguridad del auto."]'::jsonb,true,2),
('inv03','Twist 2.0 giratoria Premium Baby','giro-360','Premium Baby',0,1,'Uso: desde el nacimiento hasta los 36 kg (aprox. 12 años).Instalación con cinturón de seguridad o con ISOFIX.Orientación a contramarcha: desde el nacimiento hasta los 18 kg (aprox. 4 años)','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv03-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv03-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv03-3.jpg"]'::jsonb,'[]'::jsonb,true,3),
('inv04','Safety 1St Ellaris','convertibles','Safety 1st',0,1,'El Safety 1st Ellaris es un asiento de seguridad convertible 3 en 1 diseñado para acompañar el crecimiento de tu bebé desde recién nacido hasta la etapa de niño pequeño. Ofrece flexibilidad, un diseño delgado para ahorrar espacio y características optimizadas para facilitar los viajes.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv04-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv04-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv04-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv04-4.jpg"]'::jsonb,'["Orientación hacia atrás (Bebé): Para niños de 5 a 30 libras (aprox. 2.26 a 13.6 kg).","Orientación hacia atrás (Niño pequeño): De 30 a 40 libras.","Orientación hacia al frente: Para niños de 30 a 65 libras.","Perfil Delgado: Su diseño compacto permite instalar hasta 3 asientos en el asiento trasero de la mayoría de los vehículos.","Reclinación: Dispone de opciones de reclinado ajustables para adaptarse a las distintas orientaciones.","Movilidad: Es ligero y compacto, lo que facilita su uso al viajar desde el aeropuerto hasta el vuelo."]'::jsonb,true,4),
('inv05','Joie every stage dark pewter','convertibles','Joie',0,1,'La silla de auto Joie Every Stage (Dark Pewter) es un modelo versátil diseñado para acompañar el crecimiento de tu hijo desde el nacimiento hasta los 36 kg (aproximadamente hasta los 12 años).','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv05-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv05-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv05-3.jpg"]'::jsonb,'[]'::jsonb,true,5),
('inv06','Joie i spin multiway','giro-360','Joie',0,1,'La Joie i-Spin Multiway es una silla de coche versátil y giratoria que crece con tu hijo. Homologada     bajo la normativa i-Size (ECE R129/03), cubre desde el nacimiento hasta los 7 años aproximadamente (de 40 a 125 cm), ofreciendo seguridad, comodidad y una rotación completa de 360°.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv06-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv06-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv06-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv06-4.jpg"]'::jsonb,'["Uso Prolongado:","contramarcha: Desde el nacimiento hasta los 105 cm (hasta los 18.5 kg aproximadamente).","A favor de la marcha: Desde los 76 cm hasta los 125 cm (hasta los 25 kg).","Reclinado: Dispone de múltiples posiciones ajustables para mayor confort durante los viajes largos."]'::jsonb,true,6),
('inv07','Joie steadi r129','convertibles','Joie',0,2,'La Silla de Coche Joie Steadi R129 es un modelo del Grupo 0+/1 diseñado para niños desde el nacimiento hasta los 4 años (40 a 105 cm). Homologada bajo la estricta normativa de seguridad R129, permite viajar a contramarcha todo el período y ofrece 4 posiciones de reclinado.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv07-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv07-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv07-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv07-4.jpg"]'::jsonb,'["Seguridad certificada: Supera la norma R129, incluyendo pruebas de impacto lateral y protección integral de cabeza a pies.","Arnés de 5 puntos: Equipado con protectores suaves y sistema que distribuye las fuerzas en caso de colisión.","Sistema Grow Together: El reposacabezas y el arnés se ajustan simultáneamente en múltiples posiciones con una sola mano, sin necesidad de reposicionar los cinturones.","Reductor acolchado: Incluye un sistema de adaptadores para la cabeza y el cuerpo del bebé que aseguran su confort desde el primer día.","Reclinación: Dispone de 4 posiciones ajustables (1 a contramarcha y 3 a favor de la marcha).","Diseño compacto: Su estructura optimizada y estrecha permite aprovechar al máximo el espacio en los asientos traseros o instalar varias sillas."]'::jsonb,true,7),
('inv08','Joie Chili Spin 360','giro-360','Joie',0,1,'La silla de auto convertible Joie™ chili spin™ SI 360° rotating car seat destaca por su                      rotación de 360°, que facilita colocar y abrochar a tu hijo desde cualquier ángulo. Es una silla 2 en 1 diseñada para crecer con tu bebé, utilizable tanto a contramarcha como a favor de la marcha.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv08-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv08-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv08-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv08-4.jpg"]'::jsonb,'["Uso prolongado: Diseñada para acompañar a tu hijo desde recién nacido (aprox. 1.8 kg) hasta los primeros años escolares o un peso de 29.5 kg.","Rotación 360°: Gira hacia la puerta del vehículo para que puedas sentar, retirar y asegurar a tu hijo mirándote directamente.","Seguridad integral: Cuenta con un sistema de arnés de 5 puntos y un reposacabezas acolchado con protección reforzada contra impactos laterales.","Comodidad: Incluye telas suaves y transpirables, además de portavasos fáciles de limpiar."]'::jsonb,true,8),
('inv09','premium baby Zeus','convertibles','Premium Baby',0,3,'La Premium Baby Zeus es una silla de auto todo en uno diseñada para crecer con tu hijo desde el nacimiento hasta los 12 años (aprox. 36 kg). Se destaca por su gran adaptabilidad y confort en múltiples etapas.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv09-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv09-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv09-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv09-4.jpg"]'::jsonb,'["Etapas de Uso (Grupos 0+, 1, 2, 3):","Etapa 0-1: Orientada hacia atrás para bebés de 0 a 13 kg.","Etapa 2-3: Orientada hacia adelante para niños de 13 a 36 kg.","Seguridad: Arnés de seguridad de 5 puntos con ajuste centralizado y homologación bajo normativas europeas como la ECE R44.","Mantenimiento: Fundas desmontables y lavables para mantener una higiene óptima.","Instalación: Su diseño permite una sujeción universal mediante el cinturón de seguridad del vehículo o sistema ISOFIX (dependiendo de la versión del modelo)."]'::jsonb,true,9),
('inv10','Evenflo Nurture Max','convertibles','Evenflo',0,1,'Descripciones El Asiento de Auto Infantil Evenflo NurtureMax es una silla orientada exclusivamente hacia atrás, diseñada específicamente para adaptarse a bebés prematuros o de bajo peso y diseñada para brindar máxima seguridad y comodidad.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv10-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv10-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv10-3.jpg"]'::jsonb,'["Límite de Peso: De 4 a 22 libras (aprox. 1.8 a 10 kg).","Límite de Altura: De 17 a 29 pulgadas (aprox. 43 a 74 cm).","Peso del Asiento: Aproximadamente 6 libras, lo que la convierte en una de las sillas de su clase más ligeras para cargar.","Arnés: Sistema de arnés de 5 puntos.","Ideal para recién nacidos: La altura mínima de los hombros es de apenas 5 pulgadas, lo que permite un ajuste perfecto incluso en bebés muy pequeños.","Base con barra anti-rebote: El asiento incluye una base que se queda en el auto y cuenta con una barra diseñada para absorber y disipar las fuerzas en caso de impacto."]'::jsonb,true,10),
('inv11','Joie Saffron 4 En 1 | Thunder','convertibles','Joie',0,1,'La Joie Saffron 4 en 1 (en color Thunder) es una silla de coche diseñada para adaptarse al crecimiento de tu hijo. Ofrece 4 modos de uso y soporta desde recién nacidos hasta aproximadamente los 12 años (de 1.8 a 54 kg).','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv11-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv11-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv11-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv11-4.jpg"]'::jsonb,'["Esta versátil silla de coche cuenta con las siguientes características clave:","Orientada hacia atrás: Adecuada desde el nacimiento.","Orientada hacia adelante: Para cuando el niño crece.","Booster con respaldo alto: Proporciona elevación y protección.","Booster sin respaldo: La última etapa de uso para niños más grandes.","Protección contra impactos laterales: Equipada con cápsulas SIP que absorben la fuerza en caso de colisión."]'::jsonb,true,11),
('inv12','Booster Graham','booster','Premium Baby',0,1,'El Booster Graham de Premium Baby es un asiento elevador de seguridad para el automóvil (Grupo 3), diseñado para niños con un peso de 18 kg a 36 kg (aprox. 4 a 12 años). Garantiza que el cinturón de seguridad del vehículo pase correctamente por el hombro y la pelvis del niño.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv12-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv12-2.jpg"]'::jsonb,'["Practicidad: Incorpora portavasos laterales retráctiles para bebidas o juguetes.","Mantenimiento: El tapizado y la funda son totalmente desmontables y lavables.","Normativa: Cumple con las exigencias de seguridad homologadas (como la norma R44/04)."]'::jsonb,true,12),
('inv13','backless booster seat booster cosco arcoiris','booster','Cosco',0,1,'Un backless booster seat (asiento elevador sin respaldo) es un dispositivo de seguridad diseñado para elevar a los niños mayores y asegurar que el cinturón de seguridad del vehículo les ajuste correctamente. Proporciona la altura adicional necesaria para que el cinturón descanse sobre la clavícula y las caderas en lugar del cuello y el abdomen.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv13-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv13-2.jpg"]'::jsonb,'["A continuación, se describen sus características clave, requisitos de uso y detalles de modelos populares:","Diseño compacto y ligero: Son fáciles de mover y transferir entre diferentes vehículos.","Posicionamiento del cinturón: Guían el cinturón de seguridad (hombro y regazo) para que cruce correctamente sobre el cuerpo del niño.","Mantenimiento: Por lo general, cuentan con fundas acolchadas que se pueden quitar fácilmente y son aptas para lavadora y secadora.","Requisito de edad: Se recomienda su uso a partir de los 4 años de edad, aunque muchos expertos sugieren esperar hasta los 8 años o más.","Madurez del niño: El niño debe ser capaz de sentarse derecho y mantener el cinturón en la posición correcta durante todo el viaje sin encorvarse ni jugar con él."]'::jsonb,true,13),
('inv14','Booster Rocket','booster',null,0,1,'El Booster Rocket de Premium Baby es un asiento elevador de auto diseñado para que los niños mayores viajen con la altura adecuada para usar el cinturón de seguridad del vehículo.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv14-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv14-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv14-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv14-4.jpg"]'::jsonb,'["Grupo de Peso: Grupo III, ideal para niños que pesan entre 22 kg y 36 kg (aproximadamente de 5 a 12 años).","Diseño: Elevador sin respaldo (backless) que incluye apoyabrazos integrados y una superficie acolchada que aporta mayor comodidad durante los viajes largos.","Seguridad: Cumple con la certificación internacional ECE R44/04 y se instala a favor de la marcha utilizando el cinturón de seguridad de tres puntos del auto.","Dimensiones y Peso: El producto pesa aproximadamente 6 kg, y sus medidas son 17 cm alto × 34 cm ancho × 37 cm largo."]'::jsonb,true,14),
('inv15','Booster Bubble Bum','booster','BubbleBum',0,1,'El BubbleBum es el primer asiento elevador (booster) para automóvil, inflable y portátil, diseñado específicamente para niños de 4 a 11 años que pesan entre 40 y 100 libras (15 a 36 kg) y miden al menos 40 pulgadas (101 cm) de altura. Es la solución ideal para viajes diarios, taxis, coches compartidos y vacaciones, ya que se desinfla, se pliega y cabe fácilmente en una mochila o bolso.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv15-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv15-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv15-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv15-4.jpg"]'::jsonb,'["Inflado: Simplemente abre la válvula de aire lateral, infla el asiento soplando con la boca y cierra la válvula herméticamente.","Guardado: Para desinflarlo, abre la válvula, enrolla el asiento para expulsar todo el aire, cierra la válvula y guárdalo en su bolsa de transporte."]'::jsonb,true,15),
('inv16','BubbleBum negro','booster','BubbleBum',0,1,'El BubbleBum negro es el primer alzador para automóvil inflable y portátil del mundo. Diseñado para niños de 4 a 11 años (peso entre 15 y 36 kg), es una solución ultraligera que posiciona correctamente el cinturón de seguridad sobre el regazo y el hombro del niño.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv16-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv16-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv16-3.jpg"]'::jsonb,'["Especificaciones: Pesa tan solo 15 onzas (~0.42 kg) y sus medidas son aproximadamente 30 × 28 × 10 cm (12 × 11 × 4 pulgadas)."]'::jsonb,true,16),
('inv17','Bubble Bum Arcoiris','booster','BubbleBum',0,1,'El BubbleBum Arcoiris (Rainbow) es un asiento elevador (booster) inflable, portátil y plegable para el automóvil, diseñado para niños de 4 a 11 años (peso aproximado de 18 a 45 kg). Es ideal para viajes diarios, taxis, autos compartidos y vacaciones, ya que brinda seguridad certificada sin el volumen de un asiento rígido.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv17-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv17-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv17-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv17-4.jpg"]'::jsonb,'["Portabilidad: Se infla en segundos y es tan compacto que cabe fácilmente en una mochila, maleta, bolso de pañales o guantera. Pesa aproximadamente 15 onzas.","Comodidad: Su tecnología combina una cámara de aire con espuma viscoelástica (memory foam) que ofrece soporte estructural y evita que el niño se encorve."]'::jsonb,true,17),
('inv18','Canva Panel con diseño de mariposa','accesorios',null,0,1,'Kit de pintura creativo diseñado para niños, ideal para estimular la imaginación y el desarrollo artístico. Incluye un lienzo con diseño de mariposa para colorear, pincel y pinturas de varios colores, permitiendo a los pequeños crear su propia obra de arte de manera divertida y educativa.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv18-1.jpg"]'::jsonb,'["• Desarrollo creativo: Fomenta la imaginación, la creatividad y la expresión artística a través de la pintura.","• Motricidad fina: Ayuda a fortalecer la coordinación mano-ojo y las habilidades motoras finas mediante el uso del pincel y la aplicación de colores.","• Actividad educativa: Favorece la concentración, la paciencia y el reconocimiento de colores y formas mientras los niños se divierten.","• Materiales incluidos: Lienzo con diseño de mariposa, pincel, set de pinturas de colores y guía de referencia para inspirar la decoración.","• Fácil de usar: Diseño sencillo y atractivo, ideal para que los niños puedan pintar de forma independiente o con la ayuda de un adulto.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,18),
('inv19','Canva Panel con diseño de carro y camion','accesorios',null,0,1,'Canvas de pintura diseñado para niños con divertidos dibujos de vehículos en la carretera. Este kit permite que los pequeños exploren su creatividad mientras colorean y personalizan autos, camiones y otros medios de transporte, convirtiendo cada diseño en una obra de arte única.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv19-1.jpg"]'::jsonb,'["• Desarrollo creativo: Estimula la imaginación y la expresión artística mediante la combinación de colores y la decoración de los vehículos.","• Motricidad fina: Favorece la coordinación mano-ojo y el control de movimientos al utilizar el pincel y aplicar pintura en áreas específicas.","• Aprendizaje divertido: Ayuda a los niños a reconocer diferentes tipos de vehículos y elementos del entorno urbano de forma entretenida.","• Materiales incluidos: Lienzo preimpreso con diseño de vehículos, set de pinturas de colores, pincel y guía de referencia.","• Actividad recreativa: Ideal para compartir en familia, en la escuela o durante el tiempo libre, promoviendo la concentración y la paciencia.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,19),
('inv20','Canva Panel con diseño de monito y jirafa','accesorios',null,0,1,'Canvas de pintura infantil con un alegre diseño de jirafa y mono, ideal para que los niños desarrollen su creatividad mientras se divierten pintando. Incluye pinturas de colores y pincel para crear una obra llena de vida y color.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv20-1.jpg"]'::jsonb,'["Desarrollo creativo: Estimula la imaginación y la expresión artística al combinar colores y decorar los personajes de la selva.","Motricidad fina: Ayuda a fortalecer la coordinación mano-ojo y el control de movimientos mediante el uso del pincel.","Aprendizaje divertido: Permite a los niños reconocer animales como la jirafa y el mono de manera entretenida.","Materiales incluidos: Lienzo preimpreso con diseño de animales, set de pinturas de colores, pincel y guía de referencia.","Actividad recreativa: Ideal para el hogar, la escuela o actividades familiares, promoviendo la concentración y la paciencia.","Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,20),
('inv21','Canva Panel con diseño de dinosaurios','accesorios',null,0,1,'Canvas de pintura infantil con divertidos dinosaurios prehistóricos, diseñado para estimular la creatividad y la imaginación de los niños. Incluye pinturas de colores y pincel para que los pequeños artistas puedan dar vida a un emocionante mundo jurásico mientras desarrollan nuevas habilidades.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv21-1.jpg"]'::jsonb,'["• Desarrollo creativo: Fomenta la imaginación y la expresión artística a través de la combinación de colores y la personalización de los dinosaurios.","• Motricidad fina: Ayuda a fortalecer la coordinación mano-ojo y la precisión de los movimientos mediante el uso del pincel.","• Aprendizaje divertido: Permite a los niños conocer y reconocer diferentes tipos de dinosaurios mientras disfrutan de una actividad entretenida.","• Materiales incluidos: Lienzo preimpreso con diseño de dinosaurios, set de pinturas de colores, pincel y guía de referencia.","• Actividad educativa y recreativa: Favorece la concentración, la paciencia y la confianza en sí mismos al completar su propia obra de arte.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,21),
('inv22','Canva Panel con diseño de tigre','accesorios',null,0,1,'Canvas de pintura infantil inspirado en los animales de la selva, diseñado para que los niños exploren su creatividad mientras dan color a un simpático tigre y sus amigos. Una actividad divertida y educativa que fomenta el aprendizaje a través del arte.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv22-1.jpg"]'::jsonb,'["• Desarrollo creativo: Estimula la imaginación y la expresión artística mediante la combinación de colores y diseños.","• Motricidad fina: Ayuda a mejorar la coordinación mano-ojo y el control de movimientos al utilizar el pincel y la pintura.","• Aprendizaje sobre la naturaleza: Permite a los niños familiarizarse con los animales de la selva de una forma entretenida y educativa.","• Materiales incluidos: Lienzo preimpreso con diseño de animales, set de pinturas de colores, pincel y guía de referencia.","• Actividad recreativa: Ideal para el hogar, la escuela o actividades grupales, promoviendo la concentración, la paciencia y la creatividad.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,22),
('inv23','Canva Panel con diseño de peces','accesorios',null,0,1,'Canvas de pintura infantil con temática del océano, diseñado para que los niños exploren el fascinante mundo marino mientras desarrollan su creatividad. Incluye divertidos peces, corales y elementos submarinos que los pequeños podrán llenar de color para crear una obra única.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv23-1.jpg"]'::jsonb,'["• Desarrollo creativo: Estimula la imaginación y la expresión artística mediante la combinación de colores y diseños marinos.","• Motricidad fina: Favorece la coordinación mano-ojo y la precisión de los movimientos al utilizar el pincel y aplicar la pintura.","• Aprendizaje divertido: Ayuda a los niños a conocer la vida marina y los diferentes elementos del ecosistema submarino de forma entretenida.","• Materiales incluidos: Lienzo preimpreso con diseño marino, set de pinturas de colores, pincel y guía de referencia.","• Actividad educativa y recreativa: Promueve la concentración, la paciencia y la confianza mientras los niños completan su propia obra de arte.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,23),
('inv24','Canva Panel con diseño de Vehículos en la Ciudad','accesorios',null,0,1,'Canvas de pintura infantil con temática de transporte, ideal para que los niños desarrollen su creatividad mientras colorean divertidos vehículos en movimiento. Una actividad entretenida que combina aprendizaje, arte y diversión para los pequeños amantes de los autos y camiones.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv24-1.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv24-2.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv24-3.jpg","https://lulago3003.github.io/carseatclinicc/assets/productos/inv24-4.jpg"]'::jsonb,'["• Desarrollo creativo: Estimula la imaginación y la expresión artística mediante el uso de diferentes colores y técnicas de pintura.","• Motricidad fina: Favorece la coordinación mano-ojo y la precisión de los movimientos al utilizar el pincel y pintar dentro de las figuras.","• Aprendizaje divertido: Ayuda a los niños a reconocer distintos medios de transporte y elementos del entorno cotidiano.","• Materiales incluidos: Lienzo preimpreso con diseño de vehículos, set de pinturas de colores, pincel y guía de referencia.","• Actividad educativa y recreativa: Promueve la concentración, la paciencia y la confianza mientras los niños crean su propia obra de arte.","• Edad recomendada: Apto para niños mayores de 3 años. Se recomienda la supervisión de un adulto durante su uso."]'::jsonb,true,24),
('inv25','mouldy paint cute pets','accesorios',null,0,1,'Kit creativo de moldeado y pintura diseñado para que los niños creen y decoren adorables mascotas en yeso. Una actividad divertida y educativa que combina manualidades, arte e imaginación, permitiendo a los pequeños fabricar sus propias figuras para exhibir o regalar.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv25-1.jpg"]'::jsonb,'["• Creatividad sin límites: Los niños pueden moldear, pintar y personalizar diferentes figuras de mascotas con sus colores favoritos.","• Desarrollo de habilidades: Favorece la motricidad fina, la coordinación mano-ojo, la concentración y la creatividad.","• Aprendizaje a través del juego: Introduce conceptos básicos de arte, mezcla de colores y trabajo manual de una manera entretenida.","• Materiales incluidos: Moldes para figuras de mascotas, yeso, pinturas de colores, pincel e instrucciones paso a paso para crear las figuras.","• Actividad recreativa y educativa: Ideal para realizar en casa, en la escuela o como actividad familiar.","• Decoración y regalos: Las figuras terminadas pueden utilizarse como adornos, imanes o recuerdos hechos por los propios niños."]'::jsonb,true,25),
('inv26','Bottle Catamaran','accesorios',null,0,1,'Kit educativo de ciencia y construcción que permite a los niños crear un catamarán funcional reutilizando botellas plásticas. A través de esta divertida actividad STEM, los pequeños aprenderán principios básicos de mecánica, flotación y sostenibilidad mientras construyen su propia embarcación impulsada por una hélice.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv26-1.jpg"]'::jsonb,'["• Aprendizaje STEM: Introduce conceptos de ciencia, tecnología, ingeniería y mecánica de forma práctica y entretenida.","• Educación ambiental: Promueve la reutilización de materiales reciclables, enseñando a los niños la importancia del reciclaje y el cuidado del medio ambiente.","• Construcción interactiva: Los niños ensamblan su propio catamarán y descubren cómo funciona el sistema de propulsión mediante una hélice.","• Desarrollo de habilidades: Favorece el pensamiento lógico, la resolución de problemas, la creatividad y la coordinación manual.","• Experimento funcional: Una vez armado, el catamarán puede navegar sobre el agua, convirtiendo el aprendizaje en una experiencia divertida y práctica.","• Materiales incluidos: Piezas para el ensamblaje del catamarán e instrucciones detalladas. Las botellas plásticas se reutilizan como parte del proyecto."]'::jsonb,true,26),
('inv27','kidzlabs tornado maker','accesorios',null,0,1,'El KidzLabs Tornado Maker de 4M es un kit científico interactivo que permite a los niños construir su propio generador de tornados. Combina el aprendizaje práctico de la física y la meteorología con la reutilización de materiales, ofreciendo una experiencia educativa y visualmente fascinante.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv27-1.jpg"]'::jsonb,'["Fácil Construcción: Permite reciclar una botella de plástico vacía (como las de refresco) para ensamblarla en la base y crear un emocionante simulador de torbellinos.","Impacto Visual: Produce un torbellino de agua realista y cautivador justo en el centro de tu mesa, demostrando cómo interactúan las diferencias de presión.","Valor Educativo: Fomenta la comprensión de los fenómenos meteorológicos y las fuerzas físicas de forma entretenida.","Edad Recomendada: Apto para niños y niñas a partir de 8 años.","Alimentación: Requiere 2 baterías AA (no incluidas).","Herramientas necesarias: Un destornillador de cruz (no incluido)."]'::jsonb,true,27),
('inv28','illusion science kit','accesorios',null,0,1,'Los kits de ciencia de ilusiones (Illusion Science Kits) son juguetes educativos STEM diseñados para explorar la óptica, la percepción humana y la luz. Su objetivo es enseñar cómo el cerebro y los ojos interpretan la realidad a través de experimentos prácticos.','["https://lulago3003.github.io/carseatclinicc/assets/productos/inv28-1.jpg"]'::jsonb,'["Enfoque Educativo (STEM): Introducen conceptos básicos de óptica, refracción, difracción y percepción de manera divertida.","Experimentos y Actividades: Suelen incluir entre 9 y hasta más de 50 experimentos prácticos, dependiendo de la marca y la edición.","Edades Recomendadas: Son ideales para niños de 5 a 8 años en adelante, fomentando el pensamiento crítico y el amor por la ciencia.","Manuales Ilustrados: Incluyen guías paso a paso para que los niños puedan armar trucos y aprender de forma autónoma."]'::jsonb,true,28),
('inv29','Kidzlabs magnet Science','accesorios',null,0,1,'Kidzlabs Magnet Science (de 4M) es un kit educativo diseñado para enseñar a los niños los principios fundamentales de la física y el magnetismo a través de juegos interactivos. Está pensado para fomentar el aprendizaje práctico, la motricidad fina y la curiosidad científica en niños mayores de 8 años.','[]'::jsonb,'["El set permite transformar los imanes incluidos para realizar 10 divertidos experimentos y juegos:","Imán gigante: Construye un poderoso imán en forma de herradura o una varita magnética.","Vehículos y Movimientos: Crea un corredor súper magnético para ver cómo se mueve sin contacto físico.","Navegación: Diseña tu propia brújula en forma de yate para orientarte.","Escultura y Magia: Construye un colgante misterioso que flota y se sostiene por fuerzas magnéticas o crea esculturas.","Juegos Interactivos: Monta un divertido juego de pesca con imanes y otras actividades creativas."]'::jsonb,true,29);
